import { Menu as MenuPrimitive, useMenu } from '@ark-ui/react/menu';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { CheckIcon, ChevronDownIcon, ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import styles from './Menu.module.css';

type MenuIndicatorPosition = 'start' | 'end' | 'none';
type MenuItemTone = 'default' | 'destructive';
type MenuItemProps = ComponentProps<typeof MenuPrimitive.Item> & {
  tone?: MenuItemTone;
};
type MenuCheckboxItemProps = ComponentProps<typeof MenuPrimitive.CheckboxItem> & {
  indicator?: MenuIndicatorPosition;
};
type MenuRadioItemProps = ComponentProps<typeof MenuPrimitive.RadioItem> & {
  indicator?: MenuIndicatorPosition;
};
type MenuRootProps = ComponentProps<typeof MenuPrimitive.Root> & OverlayPortalProps;
type MenuRootProviderProps = ComponentProps<typeof MenuPrimitive.RootProvider> & OverlayPortalProps;

function MenuRoot({ portalled, portalRef, ...props }: MenuRootProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <MenuPrimitive.Root {...props} />
    </OverlayPortalProvider>
  );
}

function MenuRootProvider({ portalled, portalRef, ...props }: MenuRootProviderProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <MenuPrimitive.RootProvider {...props} />
    </OverlayPortalProvider>
  );
}

const MenuTrigger = forwardRef<
  ComponentRef<typeof MenuPrimitive.Trigger>,
  ComponentProps<typeof MenuPrimitive.Trigger>
>(function MenuTrigger({ asChild, className, ...props }, ref) {
  return (
    <MenuPrimitive.Trigger
      ref={ref}
      data-slot="menu-trigger"
      asChild={asChild}
      className={clsx(!asChild && styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

function MenuTriggerIcon({ className, children, ...props }: ComponentProps<'span'>) {
  return (
    <span data-slot="menu-trigger-icon" className={clsx(styles.triggerIcon, className)} {...props}>
      {children ?? <ChevronDownIcon className={styles.iconSvg} />}
    </span>
  );
}

const MenuIndicator = forwardRef<
  ComponentRef<typeof MenuPrimitive.Indicator>,
  ComponentProps<typeof MenuPrimitive.Indicator>
>(function MenuIndicator({ className, children, ...props }, ref) {
  return (
    <MenuPrimitive.Indicator
      ref={ref}
      data-slot="menu-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronDownIcon className={styles.iconSvg} />}
    </MenuPrimitive.Indicator>
  );
});

const MenuContextTrigger = forwardRef<
  ComponentRef<typeof MenuPrimitive.ContextTrigger>,
  ComponentProps<typeof MenuPrimitive.ContextTrigger>
>(function MenuContextTrigger({ className, ...props }, ref) {
  return (
    <MenuPrimitive.ContextTrigger
      ref={ref}
      data-slot="menu-context-trigger"
      className={clsx(styles.contextTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuPositioner = forwardRef<
  ComponentRef<typeof MenuPrimitive.Positioner>,
  ComponentProps<typeof MenuPrimitive.Positioner>
>(function MenuPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <MenuPrimitive.Positioner
        ref={ref}
        data-slot="menu-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const MenuContent = forwardRef<
  ComponentRef<typeof MenuPrimitive.Content>,
  ComponentProps<typeof MenuPrimitive.Content>
>(function MenuContent({ className, ...props }, ref) {
  return (
    <MenuPrimitive.Content
      ref={ref}
      data-slot="menu-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuArrow = forwardRef<
  ComponentRef<typeof MenuPrimitive.Arrow>,
  ComponentProps<typeof MenuPrimitive.Arrow>
>(function MenuArrow({ className, children, ...props }, ref) {
  return (
    <MenuPrimitive.Arrow
      ref={ref}
      data-slot="menu-arrow"
      className={clsx(styles.arrow, normalizeClassName(className))}
      {...props}
    >
      {children ?? <MenuArrowTip />}
    </MenuPrimitive.Arrow>
  );
});

const MenuArrowTip = forwardRef<
  ComponentRef<typeof MenuPrimitive.ArrowTip>,
  ComponentProps<typeof MenuPrimitive.ArrowTip>
>(function MenuArrowTip({ className, ...props }, ref) {
  return (
    <MenuPrimitive.ArrowTip
      ref={ref}
      data-slot="menu-arrow-tip"
      className={clsx(styles.arrowTip, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuItem = forwardRef<ComponentRef<typeof MenuPrimitive.Item>, MenuItemProps>(
  function MenuItem({ className, tone = 'default', ...props }, ref) {
    return (
      <MenuPrimitive.Item
        ref={ref}
        data-slot="menu-item"
        data-tone={tone}
        className={clsx(styles.item, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const MenuTriggerItem = forwardRef<
  ComponentRef<typeof MenuPrimitive.TriggerItem>,
  ComponentProps<typeof MenuPrimitive.TriggerItem>
>(function MenuTriggerItem({ className, children, ...props }, ref) {
  return (
    <MenuPrimitive.TriggerItem
      ref={ref}
      data-slot="menu-trigger-item"
      className={clsx(styles.triggerItem, normalizeClassName(className))}
      {...props}
    >
      {children}
    </MenuPrimitive.TriggerItem>
  );
});

function MenuTriggerItemIcon({ className, children, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-trigger-item-icon"
      className={clsx(styles.triggerItemIcon, className)}
      {...props}
    >
      {children ?? <ChevronRightIcon className={styles.iconSvg} />}
    </span>
  );
}

const MenuSeparator = forwardRef<
  ComponentRef<typeof MenuPrimitive.Separator>,
  ComponentProps<typeof MenuPrimitive.Separator>
>(function MenuSeparator({ className, ...props }, ref) {
  return (
    <MenuPrimitive.Separator
      ref={ref}
      data-slot="menu-separator"
      className={clsx(styles.separator, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuItemGroup = forwardRef<
  ComponentRef<typeof MenuPrimitive.ItemGroup>,
  ComponentProps<typeof MenuPrimitive.ItemGroup>
>(function MenuItemGroup({ className, ...props }, ref) {
  return (
    <MenuPrimitive.ItemGroup
      ref={ref}
      data-slot="menu-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuItemGroupLabel = forwardRef<
  ComponentRef<typeof MenuPrimitive.ItemGroupLabel>,
  ComponentProps<typeof MenuPrimitive.ItemGroupLabel>
>(function MenuItemGroupLabel({ className, ...props }, ref) {
  return (
    <MenuPrimitive.ItemGroupLabel
      ref={ref}
      data-slot="menu-item-group-label"
      className={clsx(styles.itemGroupLabel, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuRadioItemGroup = forwardRef<
  ComponentRef<typeof MenuPrimitive.RadioItemGroup>,
  ComponentProps<typeof MenuPrimitive.RadioItemGroup>
>(function MenuRadioItemGroup({ className, ...props }, ref) {
  return (
    <MenuPrimitive.RadioItemGroup
      ref={ref}
      data-slot="menu-radio-item-group"
      className={clsx(styles.radioItemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuRadioItem = forwardRef<ComponentRef<typeof MenuPrimitive.RadioItem>, MenuRadioItemProps>(
  function MenuRadioItem({ className, indicator = 'start', ...props }, ref) {
    return (
      <MenuPrimitive.RadioItem
        ref={ref}
        data-slot="menu-radio-item"
        data-indicator-position={indicator}
        className={clsx(styles.radioItem, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const MenuCheckboxItem = forwardRef<
  ComponentRef<typeof MenuPrimitive.CheckboxItem>,
  MenuCheckboxItemProps
>(function MenuCheckboxItem({ className, indicator = 'start', ...props }, ref) {
  return (
    <MenuPrimitive.CheckboxItem
      ref={ref}
      data-slot="menu-checkbox-item"
      data-indicator-position={indicator}
      className={clsx(styles.checkboxItem, normalizeClassName(className))}
      {...props}
    />
  );
});

const MenuItemIndicator = forwardRef<
  ComponentRef<typeof MenuPrimitive.ItemIndicator>,
  ComponentProps<typeof MenuPrimitive.ItemIndicator>
>(function MenuItemIndicator({ className, children, ...props }, ref) {
  return (
    <MenuPrimitive.ItemIndicator
      ref={ref}
      data-slot="menu-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CheckIcon className={styles.itemIndicatorIcon} />}
    </MenuPrimitive.ItemIndicator>
  );
});

const MenuItemText = forwardRef<
  ComponentRef<typeof MenuPrimitive.ItemText>,
  ComponentProps<typeof MenuPrimitive.ItemText>
>(function MenuItemText({ className, ...props }, ref) {
  return (
    <MenuPrimitive.ItemText
      ref={ref}
      data-slot="menu-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

function MenuItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-text-content"
      className={clsx(styles.itemTextContent, className)}
      {...props}
    />
  );
}

function MenuItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-text-icon"
      className={clsx(styles.itemTextIcon, className)}
      {...props}
    />
  );
}

function MenuItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-text-label"
      className={clsx(styles.itemTextLabel, className)}
      {...props}
    />
  );
}

function MenuItemShortcut({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="menu-item-shortcut"
      className={clsx(styles.itemShortcut, className)}
      {...props}
    />
  );
}

const Menu = Object.assign(MenuRoot, {
  Root: MenuRoot,
  RootProvider: MenuRootProvider,
  Trigger: MenuTrigger,
  TriggerIcon: MenuTriggerIcon,
  Indicator: MenuIndicator,
  ContextTrigger: MenuContextTrigger,
  Positioner: MenuPositioner,
  Content: MenuContent,
  Arrow: MenuArrow,
  ArrowTip: MenuArrowTip,
  Item: MenuItem,
  TriggerItem: MenuTriggerItem,
  TriggerItemIcon: MenuTriggerItemIcon,
  Separator: MenuSeparator,
  ItemGroup: MenuItemGroup,
  ItemGroupLabel: MenuItemGroupLabel,
  RadioItemGroup: MenuRadioItemGroup,
  RadioItem: MenuRadioItem,
  CheckboxItem: MenuCheckboxItem,
  ItemIndicator: MenuItemIndicator,
  ItemText: MenuItemText,
  ItemTextContent: MenuItemTextContent,
  ItemTextIcon: MenuItemTextIcon,
  ItemTextLabel: MenuItemTextLabel,
  ItemShortcut: MenuItemShortcut,
  ItemContext: MenuPrimitive.ItemContext,
});

export { Menu, useMenu };

@layer ui.components {
  .trigger,
  .contextTrigger {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--menu-trigger-gap, var(--spacing-2));
    min-height: var(--menu-trigger-height, var(--size-md));
    margin: 0;
    padding: var(--menu-trigger-padding-y, var(--spacing-1))
      var(--menu-trigger-padding-x, var(--spacing-4));
    border: var(--menu-trigger-border-width, var(--border-width-sm)) solid
      var(--menu-trigger-border-color, var(--color-border));
    border-radius: var(--menu-trigger-radius, var(--radius-md));
    background-color: var(--menu-trigger-bg, var(--color-background));
    color: var(--menu-trigger-color, var(--color-foreground));
    font: inherit;
    font-size: var(--menu-trigger-font-size, var(--text-sm));
    font-weight: var(--menu-trigger-font-weight, var(--weight-medium));
    line-height: var(--menu-trigger-line-height, var(--line-height-text-sm));
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--menu-transition, var(--transition-default)),
      border-color var(--menu-transition, var(--transition-default)),
      color var(--menu-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--menu-trigger-bg-hover);
      }
    }

    &:active {
      background-color: var(--menu-trigger-bg-active, var(--menu-trigger-bg-hover));
    }

    &[data-state='open'] {
      background-color: var(--menu-trigger-bg-active, var(--menu-trigger-bg-hover));
    }

    &:focus-visible {
      outline: var(
          --menu-focus-ring-width,
          var(--menu-trigger-border-width, var(--border-width-sm))
        )
        solid var(--menu-focus-ring-color, var(--color-ring));
      outline-offset: calc(
        var(--menu-focus-ring-width, var(--menu-trigger-border-width, var(--border-width-sm))) * -1
      );
    }

    &[data-disabled],
    &:disabled {
      pointer-events: none;
      opacity: var(--menu-disabled-opacity, var(--opacity-disabled));
    }
  }

  .contextTrigger {
    width: var(--menu-context-trigger-width, 15rem);
    min-height: var(--menu-context-trigger-height, 10rem);
    border-style: var(--menu-context-trigger-border-style, dashed);
  }

  .triggerIcon,
  .indicator {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--menu-trigger-icon-size, var(--spacing-4));
    height: var(--menu-trigger-icon-size, var(--spacing-4));
    flex-shrink: 0;
    color: var(--menu-trigger-icon-color, currentColor);
  }

  .iconSvg,
  .indicator > svg {
    width: 100%;
    height: 100%;
  }

  .positioner {
    z-index: var(--z-index);
    width: var(--positioner-width, auto);
    max-width: var(--available-width);
    outline: 0;
  }

  .content {
    --arrow-size: var(--menu-arrow-size, var(--spacing-2-5));
    --arrow-background: var(--menu-popup-bg, var(--color-popover));

    position: relative;
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    min-width: min(
      max(var(--reference-width, 0px), var(--menu-popup-min-width, 12rem)),
      var(--available-width, 100vw)
    );
    max-width: min(var(--menu-popup-max-width, 20rem), var(--available-width, 100vw));
    max-height: min(var(--menu-popup-max-height, 24rem), var(--available-height, 100dvh));
    overflow: auto;
    padding-block: var(--menu-popup-padding-y, var(--popup-list-padding-y, var(--spacing-1)));
    border-radius: var(--menu-popup-radius, var(--radius-md));
    background-color: var(--menu-popup-bg, var(--color-popover));
    color: var(--menu-popup-color, var(--color-popover-foreground));
    outline: var(--menu-popup-border-width, var(--border-width-sm)) solid
      var(--menu-popup-border-color, var(--color-border));
    box-shadow: var(--menu-popup-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    z-index: calc(var(--z-popup) + var(--layer-index, 0));

    &[data-state='open'] {
      animation: menuContentIn
        var(
          --menu-transition,
          var(--popup-motion-duration, var(--duration-normal))
            var(--popup-motion-easing, var(--ease-in-out))
        );
    }

    &[data-state='closed'] {
      animation: menuContentOut
        var(
          --menu-transition,
          var(--popup-motion-duration, var(--duration-normal))
            var(--popup-motion-easing, var(--ease-in-out))
        );
    }
  }

  .arrow {
    --arrow-background: var(--menu-popup-bg, var(--color-popover));

    z-index: -1;
  }

  .arrowTip {
    border-block-start: var(--menu-popup-border-width, var(--border-width-sm)) solid
      var(--menu-arrow-stroke-color, var(--menu-popup-border-color, var(--color-border)));
    border-inline-start: var(--menu-popup-border-width, var(--border-width-sm)) solid
      var(--menu-arrow-stroke-color, var(--menu-popup-border-color, var(--color-border)));
  }

  .item,
  .triggerItem,
  .radioItem,
  .checkboxItem {
    position: relative;
    box-sizing: border-box;
    min-height: var(--menu-item-height, var(--popup-item-min-height, var(--size-sm)));
    margin: 0;
    border: 0;
    border-radius: var(--menu-item-radius, var(--radius-sm));
    outline: 0;
    background-color: var(--menu-item-bg, transparent);
    color: inherit;
    font: inherit;
    font-size: var(--menu-item-font-size, var(--popup-item-font-size, var(--text-sm)));
    line-height: var(
      --menu-item-line-height,
      var(--popup-item-line-height, var(--line-height-text-sm))
    );
    text-decoration: none;
    user-select: none;
    cursor: default;

    &:is([data-highlighted], [data-state='open']) {
      z-index: 0;

      &::before {
        content: '';
        z-index: -1;
        position: absolute;
        inset-block: 0;
        inset-inline: var(
          --menu-highlight-inset-x,
          var(--popup-highlight-inset-x, var(--spacing-1))
        );
        border-radius: var(
          --menu-highlight-radius,
          var(--popup-highlight-radius, var(--radius-sm))
        );
        background-color: var(--menu-submenu-open-bg, var(--color-accent));
      }
    }

    &[data-highlighted] {
      color: var(--menu-highlight-color, var(--color-accent-foreground));
    }

    &[data-highlighted]::before {
      background-color: var(--menu-highlight-bg, var(--color-accent));
    }

    &[data-disabled] {
      pointer-events: none;
      background-color: var(--menu-item-bg-disabled, var(--menu-item-bg, transparent));
      color: var(--menu-item-disabled-color, var(--color-muted-foreground));
      cursor: default;
    }

    &[data-tone='destructive'] {
      color: var(--menu-item-destructive-color, var(--color-destructive));

      &[data-highlighted] {
        color: var(
          --menu-item-destructive-highlight-color,
          var(--menu-item-destructive-color, var(--color-destructive))
        );

        &::before {
          background-color: var(
            --menu-item-destructive-highlight-bg,
            color-mix(in oklab, var(--color-destructive) 12%, transparent)
          );
        }
      }
    }
  }

  .item {
    display: flex;
    align-items: center;
    gap: var(--menu-item-gap, var(--spacing-2));
    padding-block: var(--menu-item-padding-y, var(--popup-item-padding-y, var(--spacing-1)));
    padding-inline: var(
        --menu-item-padding-x-start,
        var(--popup-item-padding-x-start, var(--spacing-3))
      )
      var(--menu-item-padding-x-end, var(--popup-item-padding-x-end, var(--spacing-3)));
  }

  .triggerItem {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--menu-trigger-item-gap, var(--spacing-3));
    padding-block: var(--menu-item-padding-y, var(--popup-item-padding-y, var(--spacing-1)));
    padding-inline: var(
        --menu-item-padding-x-start,
        var(--popup-item-padding-x-start, var(--spacing-3))
      )
      var(--menu-trigger-item-padding-x-end, var(--spacing-3));
  }

  .triggerItemIcon {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--menu-trigger-item-icon-size, var(--spacing-3-5));
    height: var(--menu-trigger-item-icon-size, var(--spacing-3-5));
    flex-shrink: 0;
    color: currentColor;
  }

  .itemGroup {
    display: grid;
    padding-block: var(--menu-group-padding-y, 0);
  }

  .itemGroupLabel {
    margin: 0;
    padding-block: var(
      --menu-group-label-padding-y,
      var(--popup-group-label-padding-y, var(--spacing-1))
    );
    padding-inline: var(
        --menu-group-label-padding-x-start,
        var(--popup-group-label-padding-x-start, var(--spacing-2-5))
      )
      var(
        --menu-group-label-padding-x-end,
        var(--popup-group-label-padding-x-end, var(--spacing-3))
      );
    color: var(
      --menu-group-label-color,
      var(--popup-group-label-color, var(--color-muted-foreground))
    );
    font-size: var(
      --menu-group-label-font-size,
      var(--popup-group-label-font-size, var(--text-xs))
    );
    font-weight: var(
      --menu-group-label-font-weight,
      var(--popup-group-label-font-weight, var(--weight-regular))
    );
    line-height: var(
      --menu-group-label-line-height,
      var(--popup-group-label-line-height, var(--line-height-text-xs))
    );
    user-select: none;
    cursor: default;
  }

  .radioItemGroup {
    display: grid;
  }

  .radioItem,
  .checkboxItem {
    display: grid;
    align-items: center;
    gap: var(--menu-check-gap, var(--popup-check-gap, var(--spacing-2)));
    grid-template-columns:
      var(--menu-check-indicator-size, var(--popup-check-indicator-size, var(--spacing-3)))
      minmax(0, 1fr);
    padding-block: var(--menu-item-padding-y, var(--popup-item-padding-y, var(--spacing-1)));
    padding-inline: var(
        --menu-check-padding-x-start,
        var(--popup-check-padding-x-start, var(--spacing-2-5))
      )
      var(--menu-item-padding-x-end, var(--popup-item-padding-x-end, var(--spacing-3)));

    &[data-indicator-position='none'] {
      grid-template-columns: minmax(0, 1fr);
      padding-inline-start: var(
        --menu-item-padding-x-start,
        var(--popup-item-padding-x-start, var(--spacing-3))
      );

      & > .itemIndicator {
        display: none;
      }

      & > .itemText {
        grid-column-start: 1;
      }
    }

    &[data-indicator-position='end'] {
      grid-template-columns:
        minmax(0, 1fr)
        var(--menu-check-indicator-size, var(--popup-check-indicator-size, var(--spacing-3)));

      & > .itemText {
        grid-column-start: 1;
      }

      & > .itemIndicator {
        grid-column-start: 2;
        justify-self: end;
      }
    }
  }

  .checkboxItem[data-state='checked'] {
    > .itemIndicator {
      background-color: var(
        --menu-checkbox-indicator-bg-checked,
        var(--menu-checkbox-indicator-bg, transparent)
      );
      border-color: var(
        --menu-checkbox-indicator-border-color-checked,
        var(--menu-checkbox-indicator-border-color, currentColor)
      );
    }
  }

  .itemIndicator {
    grid-column-start: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--menu-check-indicator-size, var(--popup-check-indicator-size, var(--spacing-3)));
    height: var(--menu-check-indicator-size, var(--popup-check-indicator-size, var(--spacing-3)));
    border: var(--menu-checkbox-indicator-border-width, 0) solid
      var(--menu-checkbox-indicator-border-color, currentColor);
    border-radius: var(--menu-checkbox-indicator-radius, var(--radius-xs));
    background-color: var(--menu-checkbox-indicator-bg, transparent);

    &[data-state='checked'] {
      color: var(--menu-item-indicator-color-checked, currentColor);
    }
  }

  .itemIndicatorIcon {
    width: 100%;
    height: 100%;
  }

  .itemText {
    grid-column-start: 2;
    min-width: 0;
    overflow: hidden;
  }

  .itemTextContent {
    display: inline-flex;
    align-items: center;
    gap: var(--menu-item-text-content-gap, var(--spacing-2));
    max-width: 100%;
    min-width: 0;
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    width: var(--menu-item-text-icon-size, var(--spacing-4));
    height: var(--menu-item-text-icon-size, var(--spacing-4));
    color: var(--menu-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemShortcut {
    margin-inline-start: auto;
    padding-inline-start: var(--menu-item-shortcut-padding-x-start, var(--spacing-4));
    color: var(--menu-item-shortcut-color, var(--color-muted-foreground));
    font-size: var(--menu-item-shortcut-font-size, var(--text-xs));
    line-height: var(--menu-item-shortcut-line-height, var(--line-height-text-xs));
    white-space: nowrap;
  }

  .separator {
    box-sizing: border-box;
    height: var(--menu-separator-height, var(--border-width-sm));
    margin-block: var(
      --menu-separator-margin-y,
      var(--popup-separator-margin-y, var(--spacing-1-5))
    );
    margin-inline: var(
        --menu-separator-margin-x-start,
        var(--popup-separator-margin-x-start, var(--spacing-3))
      )
      var(--menu-separator-margin-x-end, var(--popup-separator-margin-x-end, var(--spacing-3)));
    border: 0;
    background-color: var(--menu-separator-color, var(--color-border));
  }

  @keyframes menuContentIn {
    from {
      opacity: var(--menu-popup-starting-opacity, var(--popup-motion-starting-opacity, 0));
      translate: var(--menu-popup-starting-translate-x, var(--popup-motion-starting-translate-x, 0))
        var(--menu-popup-starting-translate-y, var(--popup-motion-starting-translate-y, 0));
      transform: scale(
        var(--menu-popup-starting-scale, var(--popup-motion-starting-scale, var(--scale-popup)))
      );
    }

    to {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }
  }

  @keyframes menuContentOut {
    from {
      opacity: 1;
      translate: 0 0;
      transform: scale(1);
    }

    to {
      opacity: var(--menu-popup-ending-opacity, var(--popup-motion-ending-opacity, 0));
      translate: var(--menu-popup-ending-translate-x, var(--popup-motion-ending-translate-x, 0))
        var(--menu-popup-ending-translate-y, var(--popup-motion-ending-translate-y, 0));
      transform: scale(
        var(--menu-popup-ending-scale, var(--popup-motion-ending-scale, var(--scale-popup)))
      );
    }
  }
}
